import React, { useEffect, useState } from 'react';
import { getComplaints } from '../services/api';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import '../styles/style.css';

function AllComplaints() {
  const [complaints, setComplaints] = useState([]);
  const [searchTerm, setSearchTerm] = useState('');
  const navigate = useNavigate();

  useEffect(() => {
    const fetchData = async () => {
      try {
        const token = localStorage.getItem('token');
        const data = await getComplaints(token);
        setComplaints(data);
      } catch (err) {
        alert('Failed to fetch complaints');
      }
    };
    fetchData();
  }, []);

  const handleDelete = async (id) => {
    try {
      const token = localStorage.getItem('token');
      await axios.delete(`http://localhost:5000/complaints/${id}`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      alert('Complaint deleted successfully!');
      setComplaints(complaints.filter((complaint) => complaint._id !== id));
    } catch (error) {
      alert('Failed to delete complaint');
    }
  };

  const handleUpdate = (id) => {
    navigate(`/update/${id}`); // assumes you have an UpdateComplaint route
  };

  const filteredComplaints = complaints.filter((complaint) =>
    complaint.title.toLowerCase().includes(searchTerm.toLowerCase())
  );

  return (
    <div className="complaints-page">
      <div className="search-bar">
        <input
          type="text"
          placeholder="Search by title..."
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
        />
      </div>

      <div className="complaints-list">
        {filteredComplaints.map((complaint) => (
          <div key={complaint._id} className="complaint-card">
            <h3>{complaint.title}</h3>
            <p>{complaint.description}</p>
            {complaint.image && (
              <img src={complaint.image} alt="Complaint Visual" width="200" />
            )}

            <div className="sidebar">
              <button onClick={() => handleUpdate(complaint._id)}>Update</button>
              <button onClick={() => handleDelete(complaint._id)}>Delete</button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

export default AllComplaints;
